  `Alias` varchar(255) DEFAULT NULL,
  `Font` varchar(255) DEFAULT NULL,
  `Status` int(11) DEFAULT 1,
  `Sort` int(11) DEFAULT NULL,
  `MetaTitle` text DEFAULT NULL,
  `MetaDescription` text DEFAULT NULL,
  `MetaKeyword` text DEFAULT NULL,
  `Description` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Đang đổ dữ liệu cho bảng `page`
--

INSERT INTO `page` (`RowID`, `Name`, `Images`, `Alias`, `Font`, `Status`, `Sort`, `MetaTitle`, `MetaDescription`, `MetaKeyword`, `Description`, `created_at`, `updated_at`) VALUES
(1, 'Trang chủ', NULL, '/', '<i class=\"fas fa-home\"></i>', 1, 1, 'Trang chủ tin tức công nghệ', 'Đây là nội dung Thẻ meta description', 'Đây là nội dung Thẻ meta keyword', '<p>Meomeo</p>', '2025-02-27 08:22:57', '2025-03-12 00:01:06'),
(2, 'Về chúng tôi', NULL, 've-chung-toi', NULL, 1, 2, NULL, NULL, NULL, '<p><em><strong>VnExpress</strong></em>&nbsp;l&agrave; một tờ b&aacute;o tại&nbsp;<a href=\"https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam\" title=\"Việt Nam\">Việt Nam</a>&nbsp;được th&agrave;nh lập bởi tập đo&agrave;n&nbsp;<a href=\"https://vi.wikipedia.org/wiki/FPT\" title=\"FPT\">FPT</a>, ra mắt v&agrave;o ng&agrave;y&nbsp;<a href=\"https://vi.wikipedia.org/wiki/26_th%C3%A1ng_2\" title=\"26 tháng 2\">26 th&aacute;ng 2</a>&nbsp;năm&nbsp;<a href=\"https://vi.wikipedia.org/wiki/2001\" title=\"2001\">2001</a>&nbsp;v&agrave; hoạt động theo giấy ph&eacute;p số 548/GP-BTTTT do&nbsp;<a href=\"https://vi.wikipedia.org/wiki/B%E1%BB%99_Th%C3%B4ng_tin_v%C3%A0_Truy%E1%BB%81n_th%C3%B4ng_(Vi%E1%BB%87t_Nam)\" title=\"Bộ Thông tin và Truyền thông (Việt Nam)\">Bộ Th&ocirc;ng tin v&agrave; Truyền th&ocirc;ng</a>&nbsp;cấp ng&agrave;y 24/08/2021, hiện tại do&nbsp;<a href=\"https://vi.wikipedia.org/wiki/B%E1%BB%99_Khoa_h%E1%BB%8Dc_v%C3%A0_C%C3%B4ng_ngh%E1%BB%87_Vi%E1%BB%87t_Nam\" title=\"Bộ Khoa học và Công nghệ Việt Nam\">Bộ Khoa học v&agrave; C&ocirc;ng nghệ</a>&nbsp;quản l&yacute;. Ngo&agrave;i ra, VnExpress cũng cho ra mắt một phi&ecirc;n bản b&aacute;o điện tử Tiếng Anh để phục vụ người đọc tại nước ngo&agrave;i.<sup><a href=\"https://vi.wikipedia.org/wiki/VnExpress#cite_note-1\">[1]</a></sup></p>\r\n\r\n<p>Theo trang web&nbsp;<a href=\"https://vi.wikipedia.org/wiki/Alexa\" title=\"Alexa\">Alexa</a>, VnExpress được xếp hạng top 5 trong những trang web c&oacute; lượng truy cập nhiều nhất tại Việt Nam v&agrave;o năm 2019.</p>\r\n\r\n<p>T&ograve;a soạn của b&aacute;o được đặt tại tầng 10, t&ograve;a A FPT Tower, số 10 Phạm Văn Bạch, phường Dịch Vọng, quận Cầu Giấy, H&agrave; Nội. Văn ph&ograve;ng đại diện được đặt tại tầng 6, T&ograve;a nh&agrave; Exchange Tower - số 1 đường Nam Kỳ Khởi Nghĩa, Phường Nguyễn Th&aacute;i B&igrave;nh, Quận 1, th&agrave;nh phố Hồ Ch&iacute; Minh.</p>\r\n\r\n<p style=\"text-align:center\"><img alt=\"\" src=\"https://is.vnecdn.net/v756/60/94/84/4849460/assets/images/HUY_9499.jpeg\" style=\"height:563px; width:750px\" /></p>\r\n\r\n<h3>H&igrave;nh th&agrave;nh</h3>\r\n\r\n<p>Ng&agrave;y 26 th&aacute;ng 2 năm 2001, VnExpress ch&iacute;nh thức ra mắt website được lập tr&igrave;nh bằng ng&ocirc;n ngữ VBScript tr&ecirc;n nền tảng ứng dụng web ASP.NET, sử dụng ph&ocirc;ng chữ Unicode. Được lập tr&igrave;nh bằng ng&ocirc;n ngữ VB6 tương t&aacute;c với ActiveX Object tr&ecirc;n tr&igrave;nh duyệt Internet Explorer của Microsoft, hệ thống quản l&yacute; nội dung hoạt động như một phần mềm tr&ecirc;n m&aacute;y t&iacute;nh gi&uacute;p c&aacute;c bi&ecirc;n tập vi&ecirc;n của VnExpress c&oacute; thể thực hiện c&aacute;c thao t&aacute;c soạn thảo như tr&ecirc;n&nbsp;<a href=\"https://vi.wikipedia.org/wiki/Microsoft_Word\" title=\"Microsoft Word\">Microsoft Word</a>&nbsp;v&agrave; lưu trực tiếp tr&ecirc;n m&aacute;y.</p>\r\n\r\n<p>Tuy nhi&ecirc;n, với sự ngh&egrave;o n&agrave;n về t&iacute;nh năng của phi&ecirc;n bản HTML hiện h&agrave;nh th&igrave; ActiveX Object l&agrave; lựa chọn tối ưu nhất, nhưng cũng c&oacute; một hạn chế rất lớn l&agrave; chỉ chạy được tr&ecirc;n ch&iacute;nh Internet Explorer. Chỉ đến sau n&agrave;y khi hệ thống quản l&yacute; nội dung được n&acirc;ng cấp với c&aacute;ch tiếp cận mới hỗ trợ đa tr&igrave;nh duyệt th&igrave; to&agrave;n bộ bi&ecirc;n tập vi&ecirc;n của VnExpress mới được giải ph&oacute;ng khỏi tr&igrave;nh duyệt n&agrave;y.</p>\r\n\r\n<p>VnExpress khi mới bắt đầu đi v&agrave;o hoạt động chỉ mua b&aacute;o in về rồi cho nh&acirc;n vi&ecirc;n chọn b&agrave;i tốt, hay, hấp dẫn rồi đ&aacute;nh m&aacute;y v&agrave; đưa l&ecirc;n c&aacute;c trang nội dung của m&igrave;nh. Trong bối cảnh cả nước chưa c&oacute; b&aacute;o điện tử th&igrave; c&aacute;ch l&agrave;m n&agrave;y rất hiệu quả v&agrave; lớp độc giả ti&ecirc;n tiến nhất quen l&ecirc;n mạng bắt đầu truy cập mỗi ng&agrave;y một thường xuy&ecirc;n hơn.</p>\r\n\r\n<h3>Ph&aacute;t triển</h3>\r\n\r\n<p>Tiếp nối sự th&agrave;nh c&ocirc;ng của VnExpress, những năm 2004, 2005, c&aacute;c trang ng&aacute;ch như Ng&ocirc;i sao, Gamethu, Số h&oacute;a, hay iOne, Du lịch&hellip; li&ecirc;n tục ra đời. Điều n&agrave;y khiến cho hệ thống bắt đầu ph&igrave;nh to v&agrave; trở n&ecirc;n nặng nề, g&acirc;y kh&oacute; khăn trong việc ph&aacute;t triển c&aacute;c t&iacute;nh năng mới dựa tr&ecirc;n những c&ocirc;ng nghệ sẵn c&oacute;. Đồng thời, việc tạo ra một to&agrave; soạn hội tụ chứ kh&ocirc;ng triển khai độc lập c&aacute;c hệ thống quản l&yacute;, g&acirc;y tốn nguồn lực để duy tr&igrave; cũng l&agrave; một b&agrave;i to&aacute;n kh&oacute; m&agrave; đội ngũ c&ocirc;ng nghệ thời bấy giờ cần t&igrave;m lời giải.</p>\r\n\r\n<p>Năm 2012, VnExpress chuyển sang sử dụng m&atilde; nguồn mở. Đ&acirc;y l&agrave; một quyết định mang t&iacute;nh bước ngoặt gi&uacute;p giải quyết c&aacute;c b&agrave;i to&aacute;n cơ bản được n&ecirc;u ra ở tr&ecirc;n. Qu&aacute; tr&igrave;nh chuyển đổi hệ thống dữ liệu khổng lồ hơn mười năm của VnExpress sang m&atilde; nguồn mở k&eacute;o d&agrave;i trong một năm với y&ecirc;u cầu vừa thực hiện hoạt động chuyển đổi trong khi vẫn phải đảm bảo hệ thống trực tuyến kh&ocirc;ng một ph&uacute;t chết. Bắt đầu từ Thể Thao, Số H&oacute;a, Giải Tr&iacute; rồi Gia Đ&igrave;nh đến ng&agrave;y 15 th&aacute;ng 5 năm 2013, Kinh doanh &ndash; Chuy&ecirc;n trang cuối c&ugrave;ng cũng được chuyển đổi th&agrave;nh c&ocirc;ng, đ&aacute;nh dấu việc ho&agrave;n thiện hệ thống quản l&yacute; nội dung hội tụ.</p>\r\n\r\n<p>Song song với sự ph&aacute;t triển về số lượng độc giả, h&igrave;nh thức truy cập của người d&ugrave;ng cũng ph&aacute;t triển với xu hướng sử dụng điện thoại v&agrave; c&aacute;c thiết bị kh&aacute;c ngo&agrave;i m&aacute;y t&iacute;nh để b&agrave;n. Nắm bắt xu hướng n&agrave;y, năm 2014, VnExpress chuyển sang phong c&aacute;ch thiết kế website đ&aacute;p ứng nhu cầu hiển thị, ph&ugrave; hợp tr&ecirc;n tất cả c&aacute;c thiết bị truy cập. Đội ngũ c&ocirc;ng nghệ tiếp tục đ&oacute;ng vai tr&ograve; chủ đạo trong việc chuyển đổi hệ thống khổng lồ n&agrave;y.</p>\r\n\r\n<p>B&ecirc;n cạnh đ&oacute;, để đ&aacute;p ứng sự tăng trưởng về nội dung, n&acirc;ng cao trải nghiệm của độc giả, đội ngũ VnExpress kh&ocirc;ng ngừng nghi&ecirc;n cứu v&agrave; triển khai nhiều c&ocirc;ng nghệ mới đ&aacute;p ứng nhu cầu thể hiện nội dung bằng nhiều h&igrave;nh thức kh&aacute;c nhau như b&agrave;i e-Magazine,&nbsp;<a href=\"https://vi.wikipedia.org/wiki/Live_stream\" title=\"Live stream\">livestream trực tuyến</a>&hellip; Cũng trong thời gian gần đ&acirc;y, đội ngũ kỹ thuật của VnExpress đang nghi&ecirc;n cứu v&agrave; thử nghiệm để đưa v&agrave;o sử dụng c&aacute;c c&ocirc;ng nghệ như: Hệ thống khuyến nghị người d&ugrave;ng, trợ l&yacute; ảo, c&aacute; nh&acirc;n ho&aacute; độc giả v&agrave; ứng dụng tr&iacute; tuệ nh&acirc;n tạo trong hoạt động xuất bản nội dung ở tương lai gần.</p>\r\n\r\n<h3>Hợp nhất với b&aacute;o Khoa học v&agrave; Ph&aacute;t triển</h3>\r\n\r\n<p>Năm 2022, thực hiện&nbsp;<a href=\"https://vi.wikipedia.org/wiki/Quy_ho%E1%BA%A1ch_ph%C3%A1t_tri%E1%BB%83n_v%C3%A0_qu%E1%BA%A3n_l%C3%BD_b%C3%A1o_ch%C3%AD_to%C3%A0n_qu%E1%BB%91c_%C4%91%E1%BA%BFn_2025\" title=\"Quy hoạch phát triển và quản lý báo chí toàn quốc đến 2025\">Quy hoạch ph&aacute;t triển v&agrave; quản l&yacute; b&aacute;o ch&iacute; to&agrave;n quốc đến năm 2025</a>, B&aacute;o điện tử Tin nhanh Việt Nam (VnExpress) v&agrave; B&aacute;o Khoa học v&agrave; Ph&aacute;t triển hợp nhất th&agrave;nh B&aacute;o VnExpress.</p>', '2025-02-27 08:24:16', '2025-03-12 01:29:31'),
(3, 'Xu hướng công nghệ', NULL, 'xu-huong-cong-nghe', NULL, 1, 3, NULL, NULL, NULL, NULL, '2025-02-27 08:24:16', '2025-03-07 05:45:34'),
(4, 'Khuyến mại', NULL, 'khuyen-mai', NULL, 1, 4, NULL, NULL, NULL, NULL, '2025-02-27 08:24:46', '2025-03-07 05:45:41'),
(5, 'Liên hệ', NULL, 'lien-he', NULL, 1, 5, NULL, NULL, NULL, '<p>Ch&agrave;o mừng bạn đến với website tin tức c&ocirc;ng nghệ, nơi mang đến những tin tức c&ocirc;ng nghệ mới nhất, c&aacute;c b&agrave;i đ&aacute;nh gi&aacute; sản phẩm chuy&ecirc;n s&acirc;u v&agrave; hướng dẫn hữu &iacute;ch về thế giới c&ocirc;ng nghệ. Ch&uacute;ng t&ocirc;i lu&ocirc;n tr&acirc;n trọng mọi &yacute; kiến đ&oacute;ng g&oacute;p v&agrave; phản hồi từ độc giả để kh&ocirc;ng ngừng n&acirc;ng cao chất lượng nội dung.</p>', '2025-02-27 08:25:02', '2025-03-13 06:57:09'),
(6, 'Tìm Kiếm', NULL, 'tim-kiem', NULL, 0, 6, 'Trang tìm kiếm tin tức', 'Trang tìm kiếm tin tức', 'Trang tìm kiếm tin tức', '<p>Trang t&igrave;m kiếm tin tức</p>', '2025-03-13 03:11:17', '2025-03-12 20:12:51');

